import styles from "../page.module.css";
export default function Home() {
  return (
    <main>
      <h1 className={styles.title}>Unityでの制作</h1>

          <h2 className={styles.subtitle}>シューティングゲーム作成</h2>
          <p>pythonで始めたゲーム作りですが、スマホで動くゲームが作りたいと思い、Unityを使い始めました。
            一番最初に作ろうとしたのはpythonで作った抽象的なキャラが動くシューティングゲームです。
            ゲーム自体はかろうじて動きましたが、C#とUnityに慣れてなくてpublicと書いたらstaticと反射で書くような作り方をしていました。
            規模が大きくなっていくにつれて、コードがぐちゃぐちゃになったりそもそもUnityの座標を完全無視したSpriteRendererを書き換える方式
            がつらくなってきて、詰んだのでこのゲームの製作は一旦断念しました。
          </p>
          <h2 className={styles.subtitle}>ハクスラダンジョンゲーム作成</h2>
          <p>
            そして、次に作ろうとしたのは、よくあるハクスラダンジョンゲームです。staticが計算とかにしか使わないものであることや、
            monobehaviourの仕様を理解して、画像も毎回座標と色のクラスを使ってUnityに描かせるという重すぎる方法をやめて、
            自作のドット絵エディタにpngで出力させる方法にして、1000倍(比喩ではありません。)軽くしたり、やっとゲーム作りのスタートラインに立てたと思います。
            完成が楽しみです。
          </p>
    </main>
  );
}